from langchain_core.prompts import ChatPromptTemplate, MessagesPlaceholder
from langchain_core.messages import HumanMessage, AIMessage

prompt_template = ChatPromptTemplate(
    [("system", "你是一位乐于帮助的助理"), MessagesPlaceholder("msgs")]
)

result = prompt_template.invoke(
    {
        "msgs": [
            HumanMessage(content="我是来自上海的开发者"),
            AIMessage(content="你好，今天有什么可以帮助你的?"),
        ]
    }
)

print(type(result))
print(result)

from langgraph.graph import StateGraph, START

from typing_extensions import TypedDict


class State(TypedDict):
    input: int
    msg: str


def node_1(state: State):
    return {"msg": state.get("msg", "") + "node_1"}


def node_2(state: State):
    return {"msg": state.get("msg", "") + "node_2"}


def routing_function(state: State):
    # 通过输入的input值来决定下一个节点
    if state["input"] >= 0:
        return "node_1"
    else:
        return "node_2"


graph_builder = StateGraph(state_schema=State)
graph_builder.add_node(node_1)
graph_builder.add_node(node_2)
graph_builder.add_conditional_edges(START, routing_function)

app = graph_builder.compile()
print(app.invoke({"input": 1}))
# 输出：{'input': 1, 'msg': 'node_1'}
print(app.invoke({"input": -1}))
# 输出：{'input': -1, 'msg': 'node_2'}

import operator
from dataclasses import dataclass, field
from typing_extensions import Annotated


@dataclass(kw_only=True)
class SummaryState:
    user_query: str = field(default=None)  # original user query
    search_query: str = field(default=None)  # search query
    web_search_results: Annotated[list, operator.add] = field(default_factory=list)  # web search results
    sources_gathered: Annotated[list, operator.add] = field(default_factory=list)
    search_loop_count: int = field(default=0)  # search loop count
    running_summary: str = field(default=None)  # final report


@dataclass(kw_only=True)
class SummaryStateInput:
    user_query: str = field(default=None)


@dataclass(kw_only=True)
class SummaryStateOutput:
    running_summary: str = field(default=None)

import os
from typing import Any, Optional, Literal

from langchain_core.runnables import RunnableConfig
from pydantic import BaseModel, Field


class Configuration(BaseModel):
    max_web_search_results: int = Field(
        default=1,
        title="Max Web Search Results",
        description="Maximum number of web search results to return"
    )
    max_web_search_loops: int = Field(
        default=3,
        title="Search Depth",
        description="Number of search iterations to perform"
    )
    reasoning_llm: str = Field(
        default="deepseek-ai/DeepSeek-R1-Distill-Qwen-32B",
        title="LLM Model Name",
        description="Name of the LLM model to use"
    )
    search_api: Literal["tavily", "duckduckgo"] = Field(
        default="tavily",
        title="Search API",
        description="Web search API to use"
    )
    fetch_full_page: bool = Field(
        default=True,
        title="Fetch Full Page",
        description="Include the full page content in the search results"
    )
    strip_thinking_tokens: bool = Field(
        default=True,
        title="Strip Thinking Tokens",
        description="Whether to strip <think> tokens from model responses"
    )

    @classmethod
    def from_runnable_config(cls, config: Optional[RunnableConfig] = None) -> "Configuration":
        """Create a Configuration instance from a RunnableConfig."""
        configurable = config.configurable if hasattr(config, 'configurable') and config else {}

        raw_values: dict[str, Any] = {
            name: os.environ.get(name.upper(), configurable.get(name))
            for name in cls.model_fields.keys()
        }

        values = {k: v for k, v in raw_values.items() if v is not None}

        return cls(**values)
